const { ApolloServer, gql } = require('apollo-server');
const { v4: uuidv4 } = require('uuid');

// Mock user data
let users = [
  { id: '1', name: 'Alice' },
  { id: '2', name: 'Bob' },
  // ... more users
];

// GraphQL schema
const typeDefs = gql`
  type User {
    id: ID!
    name: String!
  }

  type Query {
    users(ids: [ID!]!): [User]
  }
`;

// Resolvers
const resolvers = {
  Query: {
    users: (parent, { ids }) => {
      return users.filter(user => ids.includes(user.id));
    },
  },
};

// Apollo Server setup
const server = new ApolloServer({ typeDefs, resolvers });

// Start the server
server.listen().then(({ url }) => {
  console.log(`🚀  Server ready at ${url}`);
});